SELECT count(*) FROM name, cast_info, aka_name, role_type, title, char_name, movie_keyword, movie_info WHERE cast_info.person_id = name.id AND aka_name.person_id = name.id AND cast_info.role_id = role_type.id AND cast_info.movie_id = title.id AND cast_info.person_role_id = char_name.id AND movie_keyword.movie_id = title.id AND movie_info.movie_id = title.id;